import{_ as e,a,b as o,c as n,d as t,e as l,f as r,g as d}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as c,o as s,c as p,a2 as u}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"Indice distribuito federato","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Other/federated-distributed-index.md","filePath":"it-IT/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),h={name:"it-IT/Other/federated-distributed-index.md"};function m(b,i,f,g,v,z){return s(),p("div",null,[...i[0]||(i[0]=[u('<h1 id="indice-distribuito-federato" tabindex="-1">Indice distribuito federato <a class="header-anchor" href="#indice-distribuito-federato" aria-label="Permalink to &quot;Indice distribuito federato&quot;">​</a></h1><p>L&#39;indice distribuito federato permette a più siti ImgBed di condividere tra loro liste di file.</p><p>In parole semplici:</p><ul><li>Puoi condividere cartelle selezionate del tuo sito con altri.</li><li>Puoi unirti a un altro nodo e sincronizzare nel tuo pannello admin la lista file condivisa da quel nodo.</li><li>I file federati servono soprattutto per navigare, cercare e aprire link. Non vengono ricaricati nel tuo storage.</li></ul><h2 id="dove-configurare" tabindex="-1">Dove configurare <a class="header-anchor" href="#dove-configurare" aria-label="Permalink to &quot;Dove configurare&quot;">​</a></h2><p>Apri:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+e+`" alt="Nodo federazione locale" loading="lazy"></p><p>La pagina ha tre schede:</p><table tabindex="0"><thead><tr><th>Scheda</th><th>Scopo</th></tr></thead><tbody><tr><td>Local Node</td><td>Abilita il tuo nodo, conferma il dominio pubblico, seleziona cartelle condivise e aggiorna l&#39;indice in uscita</td></tr><tr><td>Nodes I Joined</td><td>Gestisce altri nodi ImgBed a cui ti sei unito</td></tr><tr><td>Nodes Joining Me</td><td>Gestisce richieste di altri che vogliono unirsi al tuo nodo</td></tr></tbody></table><h2 id="prima-configurazione" tabindex="-1">Prima configurazione <a class="header-anchor" href="#prima-configurazione" aria-label="Permalink to &quot;Prima configurazione&quot;">​</a></h2><ol><li>Apri <code>Local Node</code>.</li><li>Attiva <code>Enable</code>.</li><li>Seleziona le cartelle da condividere in <code>Sync folders</code>.</li><li>Clicca <code>Update Outbound Index</code>.</li><li>Se ImgBed rileva un cambio dominio, conferma che il dominio corrente sia quello corretto prima di continuare.</li></ol><p>Puoi selezionare più cartelle di sincronizzazione.</p><p>Se la lista è vuota, vengono condivise tutte le cartelle.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="dominio-pubblico" tabindex="-1">Dominio pubblico <a class="header-anchor" href="#dominio-pubblico" aria-label="Permalink to &quot;Dominio pubblico&quot;">​</a></h3><p>Il dominio pubblico è l&#39;URL del sito che gli altri nodi usano per accedere al tuo nodo.</p><p>ImgBed lo rileva automaticamente. Non serve inserirlo a mano. La prima volta che aggiorni l&#39;indice, ImgBed chiede conferma che l&#39;URL corrente sia il dominio di produzione.</p><p>Se cambi dominio in seguito, l&#39;aggiornamento dell&#39;indice chiederà di nuovo conferma.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Le cartelle di sincronizzazione decidono quali file condividere con i nodi federati.</p><p>Per esempio, se selezioni solo:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>gli altri nodi vedranno solo i file in quelle due directory.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>Aggiorna la lista file che gli altri nodi possono sincronizzare da te.</p><p>Usalo quando:</p><ul><li>abiliti la federazione per la prima volta.</li><li>carichi file che vuoi condividere.</li><li>cambi cartelle di sincronizzazione.</li><li>cambi dominio pubblico e devi confermarlo.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> è la sezione in cui ti iscrivi ad altri nodi.</p><p><img src="`+a+'" alt="Nodi a cui mi sono unito" loading="lazy"></p><h3 id="richiedere-l-accesso-a-un-altro-nodo" tabindex="-1">Richiedere l&#39;accesso a un altro nodo <a class="header-anchor" href="#richiedere-l-accesso-a-un-altro-nodo" aria-label="Permalink to &quot;Richiedere l&#39;accesso a un altro nodo&quot;">​</a></h3><ol><li>Chiedi al proprietario un link di invito.</li><li>Incollalo nel campo.</li><li>Clicca <code>Request to Join</code>.</li><li>Attendi che l&#39;altro proprietario approvi dal suo pannello admin.</li></ol><p>Dopo l&#39;approvazione, lo stato del nodo diventa approved.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> sincronizza le liste file dai nodi a cui ti sei unito.</p><p>Usalo quando:</p><ul><li>l&#39;altro proprietario ha appena approvato la tua richiesta.</li><li>l&#39;altro proprietario ti comunica che i contenuti condivisi sono cambiati.</li><li>vuoi aggiornare tutte le liste federate unite.</li></ul><p>Per aggiornare un solo nodo, clicca <code>Update Index</code> sulla sua scheda.</p><p><img src="'+o+'" alt="Aggiorna indice" loading="lazy"></p><h3 id="annullare-l-iscrizione" tabindex="-1">Annullare l&#39;iscrizione <a class="header-anchor" href="#annullare-l-iscrizione" aria-label="Permalink to &quot;Annullare l&#39;iscrizione&quot;">​</a></h3><p>Se non vuoi più sincronizzare un nodo, clicca <code>Unsubscribe</code>.</p><p>Dopo l&#39;annullamento, l&#39;indice federato di quel nodo viene rimosso dal tuo sito locale.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> è la sezione in cui gestisci le richieste ricevute da altri.</p><p><img src="'+n+'" alt="Nodi che si uniscono a me" loading="lazy"></p><h3 id="generare-un-link-di-invito" tabindex="-1">Generare un link di invito <a class="header-anchor" href="#generare-un-link-di-invito" aria-label="Permalink to &quot;Generare un link di invito&quot;">​</a></h3><ol><li>Assicurati che il nodo locale sia abilitato.</li><li>Clicca almeno una volta <code>Update Outbound Index</code>, così ImgBed conferma il dominio pubblico.</li><li>Apri <code>Nodes Joining Me</code>.</li><li>Clicca <code>Reset Invitation Link</code>.</li><li>Copia il link di invito e invialo all&#39;altro proprietario.</li></ol><p>Se il link di invito è vuoto, di solito il dominio pubblico non è ancora stato confermato. Torna a <code>Local Node</code> e clicca <code>Update Outbound Index</code>.</p><h3 id="gestire-richieste-di-accesso" tabindex="-1">Gestire richieste di accesso <a class="header-anchor" href="#gestire-richieste-di-accesso" aria-label="Permalink to &quot;Gestire richieste di accesso&quot;">​</a></h3><p>Quando qualcuno invia una richiesta, compare nella lista <code>Nodes Joining Me</code>.</p><table tabindex="0"><thead><tr><th>Azione</th><th>Significato</th></tr></thead><tbody><tr><td>Approve</td><td>Permette all&#39;altro nodo di sincronizzare la tua lista file condivisa</td></tr><tr><td>Reject</td><td>Rifiuta la richiesta</td></tr><tr><td>Delete</td><td>Rimuove un record concluso</td></tr><tr><td>Check Status</td><td>Controlla se l&#39;altra parte mantiene ancora la relazione</td></tr></tbody></table><p>Dopo l&#39;approvazione, l&#39;altra parte deve comunque cliccare <code>Update Inbound Index</code> prima di vedere i tuoi file condivisi.</p><p><img src="'+t+'" alt="Approva nodo invitato" loading="lazy"></p><h2 id="messaggi" tabindex="-1">Messaggi <a class="header-anchor" href="#messaggi" aria-label="Permalink to &quot;Messaggi&quot;">​</a></h2><p>Dopo l&#39;approvazione di una relazione, clicca <code>Message</code> sulla scheda nodo.</p><p>I messaggi servono solo per comunicare sulla relazione federata. Non cambiano file, tag, directory o permessi.</p><p><img src="'+l+'" alt="Messaggi" loading="lazy"></p><h2 id="visualizzare-file-federati" tabindex="-1">Visualizzare file federati <a class="header-anchor" href="#visualizzare-file-federati" aria-label="Permalink to &quot;Visualizzare file federati&quot;">​</a></h2><p>Dopo la sincronizzazione, torna alla lista file admin.</p><p>In alto nella pagina puoi passare tra file locali e file federati. Nei file federati puoi sfogliare i contenuti sincronizzati.</p><p>I file federati servono per visualizzare, cercare, vedere anteprime e copiare link. Non sono file locali: non puoi spostarli, eliminarli, ritaggarli o farne backup dal tuo sito.</p><p><img src="'+r+'" alt="File federati in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="perche-mi-chiede-di-fare-di-nuovo-richiesta-perche-manca-il-record-relazione" tabindex="-1">Perché mi chiede di fare di nuovo richiesta perché manca il record relazione? <a class="header-anchor" href="#perche-mi-chiede-di-fare-di-nuovo-richiesta-perche-manca-il-record-relazione" aria-label="Permalink to &quot;Perché mi chiede di fare di nuovo richiesta perché manca il record relazione?&quot;">​</a></h3><p>Di solito significa che l&#39;altra parte ti ha eliminato e ha rimosso il record. La relazione non è più trovabile. Invia una nuova richiesta.</p><p><img src="'+d+'" alt="Nuova richiesta senza record relazione" loading="lazy"></p><h3 id="perche-non-vedo-file-dopo-l-unione" tabindex="-1">Perché non vedo file dopo l&#39;unione? <a class="header-anchor" href="#perche-non-vedo-file-dopo-l-unione" aria-label="Permalink to &quot;Perché non vedo file dopo l&#39;unione?&quot;">​</a></h3><p>Controlla:</p><ol><li>L&#39;altro proprietario ha approvato la richiesta.</li><li>L&#39;altro proprietario ha cliccato <code>Update Outbound Index</code>.</li><li>Tu hai cliccato <code>Update Inbound Index</code>.</li><li>Le cartelle di sincronizzazione dell&#39;altro proprietario includono le directory che vuole condividere.</li></ol><h3 id="cosa-fare-quando-viene-rilevato-un-cambio-dominio" tabindex="-1">Cosa fare quando viene rilevato un cambio dominio? <a class="header-anchor" href="#cosa-fare-quando-viene-rilevato-un-cambio-dominio" aria-label="Permalink to &quot;Cosa fare quando viene rilevato un cambio dominio?&quot;">​</a></h3><p>Se stai aprendo il pannello admin dal dominio di produzione, conferma e continua.</p><p>Se stai usando un indirizzo temporaneo, annulla, riapri il pannello dal dominio di produzione e riprova.</p><h3 id="cosa-significa-lista-sync-folders-vuota" tabindex="-1">Cosa significa lista Sync Folders vuota? <a class="header-anchor" href="#cosa-significa-lista-sync-folders-vuota" aria-label="Permalink to &quot;Cosa significa lista Sync Folders vuota?&quot;">​</a></h3><p>Una lista vuota significa che tutte le cartelle sono condivise.</p><p>Per condividere solo alcune directory, selezionale manualmente.</p><h3 id="differenza-tra-aggiornamento-outbound-e-inbound" tabindex="-1">Differenza tra aggiornamento outbound e inbound <a class="header-anchor" href="#differenza-tra-aggiornamento-outbound-e-inbound" aria-label="Permalink to &quot;Differenza tra aggiornamento outbound e inbound&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pulsante</th><th>Significato semplice</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Aggiorna ciò che gli altri possono sincronizzare da me</td></tr><tr><td>Update Inbound Index</td><td>Aggiorna ciò che ho sincronizzato dagli altri</td></tr></tbody></table>',78)])])}const k=c(h,[["render",m]]);export{I as __pageData,k as default};
